<?phpnamespace App\Console\Commands;use App\Models\Product;use Illuminate\Console\Command;use Illuminate\Support\Facades\Log;use Illuminate\Support\Facades\Redis;class SyncProductViews extends Command{    protected $signature = 'sync:product-views';    protected $description = 'Sync product views from Redis to database';    public function handle()    {        $prefix = config('database.redis.options.prefix');        $pattern = "{$prefix}product:views:*";        $cursor = null;        $totalSynced = 0;        do {            $result = Redis::scan($cursor, ['match' => $pattern, 'count' => 100]);            if ($result === false) {                break;            }            [$cursor, $keys] = $result;            foreach ($keys as $key) {                $id = str_replace([$prefix, 'product:views:'], '', $key);                $keyWithoutPrefix = str_replace($prefix, '', $key);                $views = Redis::get($keyWithoutPrefix);                $this->info("SCAN cursor: {$cursor}, найдено ключей: " . count($keys));                if ($views > 0) {                    Product::where('id', $id)->increment('views', $views);                    Redis::del($keyWithoutPrefix);                    $totalSynced += $views;                }            }        } while ($cursor != 0);        return 0;    }}